#result {
  display: grid;
  grid-template-rows: auto auto;
  grid-template-columns: auto 1fr;
  grid-gap: 1rem;
  -webkit-box-align: center;
      -ms-flex-align: center;
          align-items: center;
}
#result > label {
  justify-self: right;
  grid-column-start: 1;
}
#result > input {
  grid-column-start: 2;
}
#result > button {
  grid-column: 1/3;
}
