.kx-msgbox {
  position: relative;
  max-width: 450px;
  width: 80vw;
  padding: 30px 20px 20px;
  border-radius: 4px;
  overflow: hidden;
  background-color: white;
  font-size: 1rem;
  text-align: center;
}
.dialogZoomIn {
  -webkit-animation: dialog-zoomIn 0.3s 1;
          animation: dialog-zoomIn 0.3s 1;
}
@-webkit-keyframes dialog-zoomIn {
from {
    opacity: 0;
    -webkit-transform: scale(0.96, 0.96);
            transform: scale(0.96, 0.96);
}
to {
    /* default */
}
}
@keyframes dialog-zoomIn {
from {
    opacity: 0;
    -webkit-transform: scale(0.96, 0.96);
            transform: scale(0.96, 0.96);
}
to {
    /* default */
}
}
.shaking {
  -webkit-animation: shaking 0.3s 1;
          animation: shaking 0.3s 1;
}
@-webkit-keyframes shaking {
0% {
    -webkit-transform: translateX(-4px);
            transform: translateX(-4px);
}
50% {
    -webkit-transform: translateX(4px);
            transform: translateX(4px);
}
}
@keyframes shaking {
0% {
    -webkit-transform: translateX(-4px);
            transform: translateX(-4px);
}
50% {
    -webkit-transform: translateX(4px);
            transform: translateX(4px);
}
}
