.kx-dialog-icon {
  position: relative;
  width: 80px;
  height: 80px;
  border: 4px solid gray;
  border-radius: 50%;
  margin: 20px auto;
  -webkit-box-sizing: content-box;
          box-sizing: content-box;
}
.kx-dialog-icon.error {
  border-color: #ff5d64;
}
.kx-dialog-icon.error::before,
.kx-dialog-icon.error::after {
  content: "";
  display: block;
  position: absolute;
  top: 37px;
  height: 5px;
  width: 47px;
  background-color: #ff5d64;
  border-radius: 2px;
}
.kx-dialog-icon.error::before {
  -webkit-transform: rotate(45deg);
          transform: rotate(45deg);
  left: 17px;
}
.kx-dialog-icon.error::after {
  -webkit-transform: rotate(-45deg);
          transform: rotate(-45deg);
  right: 16px;
}
.kx-dialog-icon.warning {
  border-color: #ffc04c;
}
.kx-dialog-icon.warning::before {
  content: '';
  position: absolute;
  width: 5px;
  height: 29px;
  left: 50%;
  bottom: 17px;
  margin-left: -2px;
  border-radius: 2px;
  background-color: #ffc04c;
}
.kx-dialog-icon.warning::after {
  content: '';
  position: absolute;
  width: 7px;
  height: 7px;
  top: 19px;
  margin-left: -3px;
  border-radius: 50%;
  background-color: #ffc04c;
}
.kx-dialog-icon.info {
  border-color: #358bff;
}
.kx-dialog-icon.info::before {
  content: '';
  position: absolute;
  width: 5px;
  height: 29px;
  left: 50%;
  bottom: 17px;
  margin-left: -2px;
  border-radius: 2px;
  background-color: #358bff;
}
.kx-dialog-icon.info::after {
  content: '';
  position: absolute;
  width: 7px;
  height: 7px;
  top: 19px;
  margin-left: -3px;
  border-radius: 50%;
  background-color: #358bff;
}
.kx-dialog-icon.success {
  border-color: #00d936;
}
.kx-dialog-icon.success::before,
.kx-dialog-icon.success::after {
  content: "";
  display: block;
  position: absolute;
  z-index: 2;
  height: 5px;
  background-color: #00d936;
  border-radius: 2px;
}
.kx-dialog-icon.success::before {
  width: 25px;
  left: 14px;
  top: 46px;
  -webkit-transform: rotate(45deg);
          transform: rotate(45deg);
}
.kx-dialog-icon.success::after {
  width: 47px;
  right: 8px;
  top: 38px;
  -webkit-transform: rotate(-45deg);
          transform: rotate(-45deg);
}
