.kx-btn:disabled,
.kx-btn :disabled:hover {
  cursor: initial;
  pointer-events: none;
}
.kx-btn:disabled:not(.running),
.kx-btn :disabled:hover:not(.running) {
  color: dimgray;
  border-color: #d9dfdf;
  background-color: #d9dfdf;
}
.kx-btn.icon {
